import java.io.*;
import java.util.*;

public class Main {
    private static int countLessOrEqual(int[][] mat, int x) {
        int n = mat.length;
        int cnt = 0;
        int c = n - 1; // start from last column
        for (int r = 0; r < n; r++) {
            while (c >= 0 && mat[r][c] > x) {
                c--;
            }
            cnt += (c + 1);
        }
        return cnt;
    }

    private static int kthSmallest(int[][] mat, int k) {
        int left = mat[0][0];
        int right = mat[mat.length - 1][mat.length - 1];
        int ans = -1;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (countLessOrEqual(mat, mid) >= k) {
                ans = mid;
                right = mid - 1;
            } else {
                left = mid + 1;
            }
        }
        return ans;
    }

    public static void main(String[] args) throws Exception {
        // Read entire input as a string, replace any non‑numeric separators with spaces
        byte[] allBytes = System.in.readAllBytes();
        String input = new String(allBytes);
        input = input.replaceAll("[^0-9-]+", " ");
        StringTokenizer st = new StringTokenizer(input);
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int n = Integer.parseInt(st.nextToken());
            int k = Integer.parseInt(st.nextToken());
            int[][] mat = new int[n][n];
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < n; j++) {
                    mat[i][j] = Integer.parseInt(st.nextToken());
                }
            }
            int ans = kthSmallest(mat, k);
            out.append(ans);
            if (T > 0) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

